def trimmed_mean(nums):
    if not nums or len(nums) < 2:
        return None

    nums.sort()
    min_occurrences = nums[0] == nums[1] and 2
    max_occurrences = nums[-1] == nums[-2] and 2

    if not (min_occurrences or max_occurrences):
        return sum(nums[1:-1]) / len(nums[1:-1])

    if min_occurrences:
        nums.pop(0)
    if max_occurrences:
        nums.pop(-1)

    return sum(nums) / (len(nums) - 2)
